class Solution(object):
    def longestSubarray(self, nums):
        n = len(nums)
        best = 2
        cur = 2
        for i in range(2, n):
            if nums[i] == nums[i-1] + nums[i-2]:
                cur += 1
                best = max(best, cur)
            else:
                cur = 2
        return best
